#include <iostream>
#include <vector>
#include <memory>
#include <cmath>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

class Shape {
public:
    virtual double calculateArea() = 0;
    virtual ~Shape() = default;
};

class Circle : public Shape {
private:
    double rad;
public:
    Circle(double r_val) : rad(r_val) {}
    double calculateArea() override {
        double result_val = M_PI * std::pow(rad, 2.0);
        return result_val;
    }
};

class Square : public Shape {
private:
    double s_len;
public:
    Square(double len_val) : s_len(len_val) {}
    double calculateArea() override {
        return std::pow(s_len, 2.0);
    }
};

int main() {
    std::vector<std::unique_ptr<Shape>> shapes;
    shapes.push_back(std::make_unique<Circle>(5.0));
    shapes.push_back(std::make_unique<Square>(4.0));
    shapes.push_back(std::make_unique<Circle>(1.0));
    shapes.push_back(std::make_unique<Square>(10.0));
    shapes.push_back(std::make_unique<Circle>(0.0));
    shapes.push_back(std::make_unique<Square>(0.0));

    for (const auto& shape : shapes) {
        std::cout.precision(15);
        std::cout << std::fixed << shape->calculateArea() << std::endl;
    }
    return 0;
}
